column.value:
{
  "pageDescription": "Sample Creation & Registration",
  "dataPoints": {
    "sampleIdentity": {
      "sampleId": {"type": "text", "label": "Sample ID", "example": "VV-2024-001", "required": true},
      "hasBarcode": {"type": "choice", "label": "Barcode", "options": ["Yes", "No"], "required": true},
      "batchAssociation": {"type": "text", "label": "Batch Association", "required": false}
    },
    "sampleMetadata": {
      "sampleSource": {"type": "choice", "label": "Sample Source", "options": ["Human", "Animal", "Environmental", "Lab-derived"], "required": true},
      "sampleType": {"type": "reference", "label": "Sample Type", "source": "type_of_sample", "required": true},
      "receivedDateTime": {"type": "dateTime", "label": "Date & Time Received", "required": true},
      "receivedBy": {"type": "text", "label": "Received By", "required": true}
    },
    "testingIntent": {
      "testCategory": {"type": "choice", "label": "Test Category", "options": ["Viral", "Bacterial"], "required": true},
      "intendedWorkflow": {"type": "choice", "label": "Intended Workflow", "options": ["Virus culture", "Vaccine development", "Bacteriology"], "required": true},
      "priority": {"type": "choice", "label": "Priority", "options": ["Routine", "Urgent", "STAT"], "required": false},
      "projectName": {"type": "text", "label": "Project Name", "required": false}
    }
  },
  "systemActions": ["Create sample record", "Set status: Registered", "Route to Viral testing workflow", "Route to Bacteriological testing workflow"],
  "nextPage": "Viral Media Preparation"
}

{
  "pageDescription": "Viral Media Preparation",
  "dataPoints": {
    "mediaDetails": {
      "mediaType": {"type": "choice", "label": "Media Type", "options": ["Cell culture media", "Viral transport media", "Enrichment media", "Selective media", "Maintenance media"], "required": true},
      "mediaBatchNumber": {"type": "text", "label": "Media Batch Number", "required": true}
    },
    "reagentSelection": {
      "reagents": {"type": "multiSelect", "label": "Reagents Selected", "source": "reagent_inventory", "required": true},
      "reagentLotNumbers": {"type": "text", "label": "Reagent Lot Numbers", "required": false}
    },
    "equipmentDetails": {
      "equipmentUsed": {"type": "multiSelect", "label": "Equipment Used", "options": ["Biosafety cabinet", "Autoclave", "Incubator", "Water bath", "pH meter", "Balance", "Magnetic stirrer"], "required": true}
    },
    "preparationMetadata": {
      "preparedBy": {"type": "text", "label": "Prepared By", "required": true},
      "preparationDate": {"type": "date", "label": "Preparation Date", "required": true},
      "expirationDate": {"type": "date", "label": "Expiration Date", "required": false},
      "storageConditions": {"type": "choice", "label": "Storage Conditions", "options": ["Room temperature", "2-8°C", "-20°C", "-80°C"], "required": false}
    },
    "qualityControl": {
      "sterilityCheck": {"type": "choice", "label": "Sterility Check", "options": ["Pending", "Passed", "Failed"], "required": false},
      "phValue": {"type": "number", "label": "pH Value", "required": false},
      "notes": {"type": "text", "label": "Notes", "required": false}
    }
  },
  "systemActions": ["Log materials used", "Link media batch to sample", "Update inventory"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["mediaType", "reagents", "equipmentUsed", "preparedBy", "preparationDate"]
  },
  "nextPage": "Sterilization"
}
